UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=cQ4FXJQXL8s', conteudo_texto = '<h2>Gestão de Pessoas</h2><p>Área estratégica que cuida do <strong>capital humano</strong> nas organizações, essencial para concursos da Petrobras.</p><h3>👥 Conceitos Fundamentais</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p><strong>Gestão de Pessoas</strong> é o conjunto de políticas e práticas para gerenciar o comportamento humano no ambiente de trabalho.</p><p>Evolução: Departamento Pessoal → RH → Gestão de Pessoas → Gestão Estratégica de Pessoas</p></div><h3>📊 Processos de Gestão de Pessoas</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Processo</th><th style=''padding:10px;border:1px solid #ddd;''>Objetivo</th><th style=''padding:10px;border:1px solid #ddd;''>Atividades</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Agregar</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Incluir pessoas</td><td style=''padding:10px;border:1px solid #ddd;''>Recrutamento e Seleção</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Aplicar</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Desenhar atividades</td><td style=''padding:10px;border:1px solid #ddd;''>Cargos, Avaliação de Desempenho</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Recompensar</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Incentivar pessoas</td><td style=''padding:10px;border:1px solid #ddd;''>Remuneração e Benefícios</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Desenvolver</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Capacitar pessoas</td><td style=''padding:10px;border:1px solid #ddd;''>Treinamento e Desenvolvimento</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Manter</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Reter talentos</td><td style=''padding:10px;border:1px solid #ddd;''>Clima, QVT, Segurança</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Monitorar</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Acompanhar resultados</td><td style=''padding:10px;border:1px solid #ddd;''>Sistemas de Informação</td></tr></table></div><h3>🎯 Liderança</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>Estilos Clássicos</h4><ul><li><strong>Autocrático:</strong> Líder decide sozinho</li><li><strong>Democrático:</strong> Participação da equipe</li><li><strong>Liberal:</strong> Equipe decide</li></ul></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>Liderança Situacional</h4><ul><li><strong>Hersey &amp; Blanchard</strong></li><li>Adapta estilo à maturidade</li><li>Direção → Coaching → Apoio → Delegação</li></ul></div></div><h3>💡 Motivação</h3><table style=''width:100%;border-collapse:collapse;margin:15px 0;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Teoria</th><th style=''padding:10px;border:1px solid #ddd;''>Autor</th><th style=''padding:10px;border:1px solid #ddd;''>Conceito-chave</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Hierarquia das Necessidades</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Maslow</td><td style=''padding:10px;border:1px solid #ddd;''>Pirâmide: fisiológicas → segurança → sociais → estima → autorrealização</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Dois Fatores</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Herzberg</td><td style=''padding:10px;border:1px solid #ddd;''>Higiênicos (evitam insatisfação) × Motivacionais (geram satisfação)</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>X e Y</strong></td><td style=''padding:10px;border:1px solid #ddd;''>McGregor</td><td style=''padding:10px;border:1px solid #ddd;''>X (pessoas evitam trabalho) × Y (pessoas gostam de trabalho)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Expectativa</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Vroom</td><td style=''padding:10px;border:1px solid #ddd;''>Valência × Expectativa × Instrumentalidade</td></tr></table><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Cesgranrio adora cobrar a diferença entre <strong>Maslow</strong> (hierarquia rígida) e <strong>Herzberg</strong> (dois fatores independentes)!</p></div>' WHERE titulo = 'Resumo: Gestão de Pessoas';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=H0_yKBitO8M', conteudo_texto = '<h2>Gestão de Projetos</h2><p>Conhecimentos em <strong>PMBOK</strong> e <strong>metodologias ágeis</strong> são muito cobrados em concursos da Petrobras.</p><h3>📘 Conceitos Básicos</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><ul><li><strong>Projeto:</strong> Esforço temporário para criar um produto, serviço ou resultado único.</li><li><strong>Programa:</strong> Conjunto de projetos relacionados.</li><li><strong>Portfólio:</strong> Conjunto de projetos e programas alinhados à estratégia.</li><li><strong>PMO:</strong> Escritório de Gerenciamento de Projetos.</li></ul></div><h3>📊 Grupos de Processos (PMBOK)</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Grupo</th><th style=''padding:10px;border:1px solid #ddd;''>Objetivo</th><th style=''padding:10px;border:1px solid #ddd;''>Entregas Principais</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Iniciação</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Autorizar o projeto</td><td style=''padding:10px;border:1px solid #ddd;''>Termo de Abertura, Stakeholders</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Planejamento</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Definir escopo e plano</td><td style=''padding:10px;border:1px solid #ddd;''>Plano de Gerenciamento, EAP, Cronograma</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Execução</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Realizar o trabalho</td><td style=''padding:10px;border:1px solid #ddd;''>Entregas, Equipe mobilizada</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Monitoramento e Controle</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Acompanhar e corrigir</td><td style=''padding:10px;border:1px solid #ddd;''>Relatórios, Mudanças aprovadas</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Encerramento</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Finalizar formalmente</td><td style=''padding:10px;border:1px solid #ddd;''>Aceite final, Lições aprendidas</td></tr></table></div><h3>🔟 Áreas de Conhecimento</h3><div style=''display:flex;flex-wrap:wrap;gap:10px;margin:15px 0;''><span style=''background:#28a745;color:white;padding:8px 12px;border-radius:20px;''>Integração</span><span style=''background:#17a2b8;color:white;padding:8px 12px;border-radius:20px;''>Escopo</span><span style=''background:#ffc107;color:black;padding:8px 12px;border-radius:20px;''>Cronograma</span><span style=''background:#dc3545;color:white;padding:8px 12px;border-radius:20px;''>Custos</span><span style=''background:#6f42c1;color:white;padding:8px 12px;border-radius:20px;''>Qualidade</span><span style=''background:#e83e8c;color:white;padding:8px 12px;border-radius:20px;''>Recursos</span><span style=''background:#20c997;color:white;padding:8px 12px;border-radius:20px;''>Comunicações</span><span style=''background:#fd7e14;color:white;padding:8px 12px;border-radius:20px;''>Riscos</span><span style=''background:#6c757d;color:white;padding:8px 12px;border-radius:20px;''>Aquisições</span><span style=''background:#007bff;color:white;padding:8px 12px;border-radius:20px;''>Stakeholders</span></div><h3>🚀 Metodologias Ágeis</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:250px;background:#d4edda;padding:15px;border-radius:8px;border-left:4px solid #28a745;''><h4>📋 SCRUM</h4><ul><li><strong>Sprint:</strong> Ciclo de 2-4 semanas</li><li><strong>Product Owner:</strong> Define o que fazer</li><li><strong>Scrum Master:</strong> Remove impedimentos</li><li><strong>Dev Team:</strong> Executa o trabalho</li><li><strong>Backlog:</strong> Lista de requisitos</li></ul></div><div style=''flex:1;min-width:250px;background:#fff3cd;padding:15px;border-radius:8px;border-left:4px solid #ffc107;''><h4>📊 KANBAN</h4><ul><li><strong>Quadro visual:</strong> To Do → Doing → Done</li><li><strong>WIP Limit:</strong> Limite de trabalho em progresso</li><li><strong>Fluxo contínuo:</strong> Sem sprints fixos</li><li><strong>Melhoria contínua:</strong> Kaizen</li></ul></div></div><h3>📐 Ferramentas Importantes</h3><table style=''width:100%;border-collapse:collapse;margin:15px 0;''><tr style=''background:#6c757d;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Ferramenta</th><th style=''padding:10px;border:1px solid #ddd;''>Uso</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>EAP (WBS)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Decomposição do escopo em entregas</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Gráfico de Gantt</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Cronograma visual com barras</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>PERT/CPM</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Caminho crítico e duração</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Matriz RACI</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Responsabilidades (Responsible, Accountable, Consulted, Informed)</td></tr></table><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>A Cesgranrio cobra muito a <strong>Tríplice Restrição</strong>: Escopo × Tempo × Custo. Alteração em um afeta os outros!</p></div>' WHERE titulo = 'Resumo: Gestão de Projetos';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=Mi1QBxVjZAw', conteudo_texto = '<h2>Logística e Supply Chain</h2><p>Gestão da <strong>cadeia de suprimentos</strong> e fluxo de materiais, fundamental para operações da Petrobras.</p><h3>📦 Conceitos Fundamentais</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><ul><li><strong>Logística:</strong> Planejamento e controle do fluxo de materiais, informações e recursos.</li><li><strong>Supply Chain:</strong> Cadeia completa desde fornecedores até o cliente final.</li><li><strong>SCM:</strong> Supply Chain Management - gestão integrada da cadeia.</li></ul></div><h3>🔄 Fluxos da Cadeia de Suprimentos</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:150px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>📦 Materiais</strong><p>Fornecedor → Empresa → Cliente</p></div><div style=''flex:1;min-width:150px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>💰 Financeiro</strong><p>Cliente → Empresa → Fornecedor</p></div><div style=''flex:1;min-width:150px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>📊 Informação</strong><p>Bidirecional em toda cadeia</p></div></div><h3>📊 Atividades Logísticas</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Atividade</th><th style=''padding:10px;border:1px solid #ddd;''>Descrição</th><th style=''padding:10px;border:1px solid #ddd;''>Indicadores</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Gestão de Estoques</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Controle de níveis e custos</td><td style=''padding:10px;border:1px solid #ddd;''>Giro, Cobertura, Acuracidade</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Armazenagem</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Guarda e movimentação</td><td style=''padding:10px;border:1px solid #ddd;''>Ocupação, Produtividade</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Transporte</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Movimentação entre locais</td><td style=''padding:10px;border:1px solid #ddd;''>Custo/km, Lead time</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Compras</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Aquisição de materiais</td><td style=''padding:10px;border:1px solid #ddd;''>Saving, Lead time fornecedor</td></tr></table></div><h3>📈 Modelos de Gestão de Estoques</h3><table style=''width:100%;border-collapse:collapse;margin:15px 0;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Modelo</th><th style=''padding:10px;border:1px solid #ddd;''>Característica</th><th style=''padding:10px;border:1px solid #ddd;''>Quando usar</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>LEC (Lote Econômico)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Quantidade ótima de compra</td><td style=''padding:10px;border:1px solid #ddd;''>Demanda estável</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Just in Time (JIT)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Estoque mínimo, entrega no momento</td><td style=''padding:10px;border:1px solid #ddd;''>Produção enxuta</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>MRP</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Planejamento de necessidades</td><td style=''padding:10px;border:1px solid #ddd;''>Demanda dependente</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Curva ABC</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Classificação por importância</td><td style=''padding:10px;border:1px solid #ddd;''>Priorização de itens</td></tr></table><h3>🏷️ Curva ABC (Pareto)</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #ffc107;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Classe</th><th style=''padding:10px;border:1px solid #ddd;''>% Itens</th><th style=''padding:10px;border:1px solid #ddd;''>% Valor</th><th style=''padding:10px;border:1px solid #ddd;''>Controle</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>A</strong></td><td style=''padding:10px;border:1px solid #ddd;''>20%</td><td style=''padding:10px;border:1px solid #ddd;''>80%</td><td style=''padding:10px;border:1px solid #ddd;''>Rigoroso</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>B</strong></td><td style=''padding:10px;border:1px solid #ddd;''>30%</td><td style=''padding:10px;border:1px solid #ddd;''>15%</td><td style=''padding:10px;border:1px solid #ddd;''>Intermediário</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>C</strong></td><td style=''padding:10px;border:1px solid #ddd;''>50%</td><td style=''padding:10px;border:1px solid #ddd;''>5%</td><td style=''padding:10px;border:1px solid #ddd;''>Simplificado</td></tr></table></div><h3>🚢 Modais de Transporte</h3><div style=''display:flex;flex-wrap:wrap;gap:10px;margin:15px 0;''><span style=''background:#007bff;color:white;padding:8px 12px;border-radius:20px;''>🚛 Rodoviário</span><span style=''background:#28a745;color:white;padding:8px 12px;border-radius:20px;''>🚂 Ferroviário</span><span style=''background:#17a2b8;color:white;padding:8px 12px;border-radius:20px;''>🚢 Aquaviário</span><span style=''background:#ffc107;color:black;padding:8px 12px;border-radius:20px;''>✈️ Aéreo</span><span style=''background:#6c757d;color:white;padding:8px 12px;border-radius:20px;''>🔵 Dutoviário</span></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Na Petrobras, o modal <strong>dutoviário</strong> é essencial para transporte de petróleo e derivados. É o mais econômico para grandes volumes!</p></div>' WHERE titulo = 'Resumo: Logística e Supply Chain';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=oPMTGhEPuQs', conteudo_texto = '<h2>Contabilidade Básica</h2><p>Conceitos contábeis essenciais para administradores e concursos da Petrobras.</p><h3>📘 Conceitos Fundamentais</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><ul><li><strong>Contabilidade:</strong> Ciência que registra, controla e analisa o patrimônio das entidades.</li><li><strong>Patrimônio:</strong> Conjunto de bens, direitos e obrigações.</li><li><strong>Exercício Social:</strong> Período de 12 meses para apuração de resultados.</li></ul></div><h3>⚖️ Equação Patrimonial</h3><div style=''background:#d4edda;padding:20px;border-radius:8px;margin:15px 0;text-align:center;''><h3 style=''color:#28a745;''>ATIVO = PASSIVO + PATRIMÔNIO LÍQUIDO</h3><p>ou</p><h4>Bens + Direitos = Obrigações + Capital Próprio</h4></div><h3>📊 Estrutura do Balanço Patrimonial</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:250px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4 style=''color:#0066cc;''>ATIVO (Aplicações)</h4><p><strong>Circulante</strong> (curto prazo)</p><ul><li>Caixa e Bancos</li><li>Contas a Receber</li><li>Estoques</li></ul><p><strong>Não Circulante</strong> (longo prazo)</p><ul><li>Realizável a LP</li><li>Investimentos</li><li>Imobilizado</li><li>Intangível</li></ul></div><div style=''flex:1;min-width:250px;background:#f8d7da;padding:15px;border-radius:8px;''><h4 style=''color:#dc3545;''>PASSIVO (Origens)</h4><p><strong>Circulante</strong> (curto prazo)</p><ul><li>Fornecedores</li><li>Empréstimos CP</li><li>Salários a Pagar</li></ul><p><strong>Não Circulante</strong> (longo prazo)</p><ul><li>Empréstimos LP</li><li>Debêntures</li></ul><p><strong>Patrimônio Líquido</strong></p><ul><li>Capital Social</li><li>Reservas</li><li>Lucros/Prejuízos</li></ul></div></div><h3>📈 Demonstração do Resultado (DRE)</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><td colspan=''2'' style=''padding:10px;border:1px solid #ddd;''><strong>RECEITA BRUTA</strong></td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>(-) Deduções</td><td style=''padding:10px;border:1px solid #ddd;''>Impostos, devoluções</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>= RECEITA LÍQUIDA</strong></td><td style=''padding:10px;border:1px solid #ddd;''></td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>(-) CMV/CPV</td><td style=''padding:10px;border:1px solid #ddd;''>Custo da mercadoria/produto</td></tr><tr style=''background:#d4edda;''><td style=''padding:10px;border:1px solid #ddd;''><strong>= LUCRO BRUTO</strong></td><td style=''padding:10px;border:1px solid #ddd;''></td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>(-) Despesas Operacionais</td><td style=''padding:10px;border:1px solid #ddd;''>Administrativas, Vendas</td></tr><tr style=''background:#fff3cd;''><td style=''padding:10px;border:1px solid #ddd;''><strong>= LUCRO OPERACIONAL</strong></td><td style=''padding:10px;border:1px solid #ddd;''></td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>(±) Resultado Financeiro</td><td style=''padding:10px;border:1px solid #ddd;''>Juros, variação cambial</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''>(-) IR e CSLL</td><td style=''padding:10px;border:1px solid #ddd;''>Impostos sobre lucro</td></tr><tr style=''background:#0066cc;color:white;''><td style=''padding:10px;border:1px solid #ddd;''><strong>= LUCRO LÍQUIDO</strong></td><td style=''padding:10px;border:1px solid #ddd;''></td></tr></table></div><h3>📐 Princípios Contábeis</h3><table style=''width:100%;border-collapse:collapse;margin:15px 0;''><tr style=''background:#6c757d;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Princípio</th><th style=''padding:10px;border:1px solid #ddd;''>Significado</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Entidade</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Patrimônio da empresa ≠ dos sócios</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Continuidade</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Empresa funciona indefinidamente</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Competência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Registro quando o fato ocorre (não quando paga)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Prudência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Menor valor para ativos, maior para passivos</td></tr></table><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Memorize: <strong>Ativo = Débito aumenta</strong> | <strong>Passivo/PL = Crédito aumenta</strong>. Essa é a base dos lançamentos contábeis!</p></div>' WHERE titulo = 'Resumo: Contabilidade Básica';